// demux_decode.c - فصل الـ streams ثم فك الترميز
#include <libavcodec/avcodec.h>
#include <libavformat/avformat.h>
#include <stdio.h>

int main(int argc, char **argv) {
    const char *filename = argc > 1 ? argv[1] : "input.mkv";
    AVFormatContext *fmt_ctx = NULL;
    AVPacket *pkt = av_packet_alloc();
    AVFrame *frame = av_frame_alloc();

    // 1. فتح الملف
    avformat_open_input(&fmt_ctx, filename, NULL, NULL);
    avformat_find_stream_info(fmt_ctx, NULL);

    printf("Streams: %d\n", fmt_ctx->nb_streams);

    // 2. لكل stream: إيجاد decoder وطباعة معلوماته
    for (unsigned i = 0; i < fmt_ctx->nb_streams; i++) {
        AVStream *stream = fmt_ctx->streams[i];
        AVCodecParameters *par = stream->codecpar;
        const AVCodec *codec = avcodec_find_decoder(par->codec_id);
        if (!codec) {
            printf("Stream #%d: codec غير مدعوم (id=%d)\n", i, par->codec_id);
            continue;
        }

        AVCodecContext *ctx = avcodec_alloc_context3(codec);
        avcodec_parameters_to_context(ctx, par);
n        avcodec_open2(ctx, codec, NULL);

        printf("Stream #%d: %s (%s)\n", i, codec->long_name,
               av_get_media_type_string(par->codec_type));

        // 3. فك الترميز الـ packets الخاصة بهذا الـ stream
        while (av_read_frame(fmt_ctx, pkt) >= 0) {
            if (pkt->stream_index == (int)i) {
                avcodec_send_packet(ctx, pkt);
                while (avcodec_receive_frame(ctx, frame) >= 0) {
                    printf("  [%s] frame pts=%ld\n", codec->long_name, frame->pts);
                }
            }
            av_packet_unref(pkt);
        }

        avcodec_free_context(&ctx);
    }

    av_frame_free(&frame);
    av_packet_free(&pkt);
    avformat_close_input(&fmt_ctx);
    return 0;
}

